     2→import { parseMDX } from 'war3-model';
     3→
     4→const components = [
     5→  { name: 'GoldButton', size: 1.2 },
     6→  { name: 'ResourceCounter', size: 0.8 },
     7→  { name: 'CommandCard', size: 1.9 },
     8→  { name: 'Tooltip', size: 1.4 },
     9→  { name: 'PortraitFrame', size: 1.1 },
    10→  { name: 'HealthBar', size: 0.6 },
    11→  { name: 'Minimap', size: 2.1 },
    12→  { name: 'Dialog', size: 1.7 },
    13→  { name: 'ChatBubble', size: 0.9 },
