    17→const maxSize = Math.max(...components.map((c) => c.size));
    18→const imageCache = new Map<string, Promise<HTMLImageElement>>();
    19→const buildProgressBarModelPath = '/models/build-progress/BuildProgressBar.mdx';
    20→const fallbackCapRatio = 4 / 128;
    21→let buildProgressBarUvPromise: Promise<{ minU: number; maxU: number }> | null = null;
    22→
    23→interface Props {
    24→  buildFillUrl: Accessor<string>;
    25→  buildBorderUrl: Accessor<string>;
    26→}
    27→
    28→interface BuildProgressRowBarProps {
    29→  valuePct: number;
    30→  fillUrl: Accessor<string>;
    31→  borderUrl: Accessor<string>;
    32→}
    33→
    34→function normalizeTexturePath(path: string): string {
    35→  return path.replace(/\\/g, '/').toLowerCase();
    36→}
    37→
    38→async function loadBuildProgressBarUvDomain(): Promise<{ minU: number; maxU: number }> {
    39→  if (buildProgressBarUvPromise) return buildProgressBarUvPromise;
    40→
    41→  buildProgressBarUvPromise = (async () => {
    42→    const fallback = { minU: 0, maxU: 1 };
    43→    try {
    44→      const res = await fetch(buildProgressBarModelPath);
    45→      if (!res.ok) return fallback;
    46→      const ab = await res.arrayBuffer();
    47→      const model: any = parseMDX(ab);
    48→      const textures: Array<{ Image?: string }> = model.Textures || [];
    49→      const borderTexIndex = textures.findIndex((tex) =>
    50→        normalizeTexturePath(String(tex?.Image || '')).endsWith('/human-buildprogressbar-border2.blp'),
    51→      );
    52→      if (borderTexIndex < 0) return fallback;
    53→
    54→      const materials: Array<{ Layers?: Array<{ TextureID?: number }> }> = model.Materials || [];
    55→      const borderMaterialIndex = materials.findIndex((material) =>
    56→        (material?.Layers || []).some((layer) => layer?.TextureID === borderTexIndex),
    57→      );
    58→      if (borderMaterialIndex < 0) return fallback;
    59→
    60→      const geosets: Array<{ MaterialID?: number; TVertices?: number[][] }> = model.Geosets || [];
    61→      const borderGeoset = geosets.find((geoset) => geoset.MaterialID === borderMaterialIndex);
    62→      const uv = borderGeoset?.TVertices?.[0];
    63→      if (!uv || uv.length < 2) return fallback;
    64→
    65→      let minU = Infinity;
    66→      let maxU = -Infinity;
    67→      for (let i = 0; i < uv.length; i += 2) {
    68→        const u = uv[i];
    69→        if (u < minU) minU = u;
    70→        if (u > maxU) maxU = u;
    71→      }
    72→      if (!Number.isFinite(minU) || !Number.isFinite(maxU) || maxU <= minU) return fallback;
    73→      return { minU, maxU };
    74→    } catch (err) {
    75→      console.warn('Failed to load BuildProgressBar UV domain, falling back to texture-domain caps.', err);
    76→      return fallback;
    77→    }
    78→  })();
    79→
    80→  return buildProgressBarUvPromise;
    81→}
    82→
    83→async function loadDataUrlImage(url: string): Promise<HTMLImageElement> {
    84→  const cached = imageCache.get(url);
    85→  if (cached) return cached;
    86→  const promise = new Promise<HTMLImageElement>((resolve, reject) => {
    87→    const img = new Image();
    88→    img.onload = () => resolve(img);
    89→    img.onerror = () => reject(new Error(`Failed to load image ${url}`));
    90→    img.src = url;
    91→  });
    92→  imageCache.set(url, promise);
    93→  return promise;
    94→}
    95→
    96→function deriveBuildBarCapRatio(
    97→  borderImg: HTMLImageElement,
    98→  uvDomain: { minU: number; maxU: number },
    99→): number {
   100→  const width = borderImg.width;
   101→  const height = borderImg.height;
   102→  if (width <= 2 || height <= 0) return fallbackCapRatio;
   103→
   104→  const scratch = document.createElement('canvas');
   105→  scratch.width = width;
   106→  scratch.height = height;
   107→  const scratchCtx = scratch.getContext('2d', { willReadFrequently: true });
   108→  if (!scratchCtx) return fallbackCapRatio;
   109→
   110→  scratchCtx.clearRect(0, 0, width, height);
   111→  scratchCtx.drawImage(borderImg, 0, 0);
   112→  const data = scratchCtx.getImageData(0, 0, width, height).data;
   113→  const row = Math.floor(height / 2);
   114→
   115→  const alphaAt = (x: number) => data[(row * width + x) * 4 + 3];
   116→  let firstOpaque = 0;
   117→  while (firstOpaque < width && alphaAt(firstOpaque) === 0) firstOpaque += 1;
   118→
   119→  let firstGap = firstOpaque;
   120→  while (firstGap < width && alphaAt(firstGap) !== 0) firstGap += 1;
   121→  if (firstGap <= firstOpaque || firstGap >= width) return fallbackCapRatio;
   122→
   123→  const uSpan = Math.max(1e-6, uvDomain.maxU - uvDomain.minU);
   124→  const uAtGap = firstGap / width;
   125→  const ratio = (uAtGap - uvDomain.minU) / uSpan;
   126→  return Math.max(1 / width, Math.min(0.45, ratio));
   127→}
   128→
   129→function drawThreeSliceTextureToCanvas(
   130→  ctx: CanvasRenderingContext2D,
   131→  img: HTMLImageElement,
   132→  x: number,
   133→  y: number,
   134→  width: number,
   135→  height: number,
   136→  capPx: number,
   137→) {
   138→  if (width <= 0 || height <= 0) return;
   139→
   140→  const srcW = img.width;
   141→  const srcH = img.height;
   142→  const srcCap = Math.min(capPx, Math.floor(srcW / 2));
   143→  const dstCap = Math.min(srcCap, Math.floor(width / 2));
   144→
   145→  if (dstCap > 0) {
   146→    ctx.drawImage(img, 0, 0, srcCap, srcH, x, y, dstCap, height);
   147→  }
   148→
   149→  const dstCenterW = width - dstCap * 2;
   150→  if (dstCenterW > 0) {
   151→    const srcCenterX = srcCap;
   152→    const srcCenterW = Math.max(1, srcW - srcCap * 2);
   153→    ctx.drawImage(img, srcCenterX, 0, srcCenterW, srcH, x + dstCap, y, dstCenterW, height);
   154→  }
   155→
   156→  if (dstCap > 0) {
   157→    ctx.drawImage(img, srcW - srcCap, 0, srcCap, srcH, x + width - dstCap, y, dstCap, height);
   158→  }
   159→}
   160→
   161→function drawBuildProgressBarToCanvas(
   162→  canvas: HTMLCanvasElement,
   163→  fillImg: HTMLImageElement,
   164→  borderImg: HTMLImageElement,
   165→  valuePct: number,
   166→  capRatio: number,
   167→) {
   168→  const rect = canvas.getBoundingClientRect();
   169→  const cssW = Math.max(1, rect.width);
   170→  const cssH = Math.max(1, rect.height);
   171→  const dpr = window.devicePixelRatio || 1;
   172→  const pxW = Math.max(1, Math.round(cssW * dpr));
   173→  const pxH = Math.max(1, Math.round(cssH * dpr));
   174→  if (canvas.width !== pxW || canvas.height !== pxH) {
   175→    canvas.width = pxW;
   176→    canvas.height = pxH;
   177→  }
   178→
   179→  const ctx = canvas.getContext('2d');
   180→  if (!ctx) return;
   181→  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
   182→  ctx.clearRect(0, 0, cssW, cssH);
   183→  ctx.imageSmoothingEnabled = true;
   184→  const capPx = Math.max(1, Math.round(cssW * capRatio));
   185→
   186→  const fillW = Math.max(0, Math.min(cssW, (valuePct / 100) * cssW));
   187→  if (fillW > 0) {
   188→    drawThreeSliceTextureToCanvas(ctx, fillImg, 0, 0, fillW, cssH, capPx);
   189→  }
   190→
   191→  drawThreeSliceTextureToCanvas(ctx, borderImg, 0, 0, cssW, cssH, capPx);
   192→}
   193→
   194→function BuildProgressRowBar(props: BuildProgressRowBarProps) {
   195→  let canvasRef!: HTMLCanvasElement;
   196→  let renderNonce = 0;
   197→  let destroyed = false;
   198→
   199→  const renderBar = async () => {
   200→    const canvas = canvasRef;
   201→    if (!canvas || destroyed) return;
   202→    const fillUrl = props.fillUrl();
   203→    const borderUrl = props.borderUrl();
   204→    const currentNonce = ++renderNonce;
   205→
   206→    if (!fillUrl || !borderUrl) {
   207→      const ctx = canvas.getContext('2d');
   208→      if (ctx) {
   209→        ctx.clearRect(0, 0, canvas.width, canvas.height);
   210→      }
   211→      return;
   212→    }
   213→
   214→    try {
   215→      const [fillImg, borderImg, uvDomain] = await Promise.all([
   216→        loadDataUrlImage(fillUrl),
   217→        loadDataUrlImage(borderUrl),
   218→        loadBuildProgressBarUvDomain(),
   219→      ]);
   220→      if (destroyed || currentNonce !== renderNonce) return;
   221→      const capRatio = deriveBuildBarCapRatio(borderImg, uvDomain);
   222→      drawBuildProgressBarToCanvas(canvas, fillImg, borderImg, props.valuePct, capRatio);
   223→    } catch (err) {
   224→      console.error(err);
   225→    }
   226→  };
   227→
   228→  createEffect(() => {
   229→    props.valuePct;
   230→    props.fillUrl();
   231→    props.borderUrl();
   232→    void renderBar();
   233→  });
   234→
   235→  onMount(() => {
   236→    const resizeObserver = new ResizeObserver(() => {
   237→      void renderBar();
   238→    });
   239→    resizeObserver.observe(canvasRef);
   240→
   241→    onCleanup(() => {
   242→      destroyed = true;
   243→      resizeObserver.disconnect();
   244→    });
   245→  });
   246→
   247→  return <canvas ref={canvasRef} class="bundle-chart-bar-canvas" />;
   248→}
