   250→export default function BundleSizeSection(props: Props) {
   251→  return (
   252→    <section class="section-card">
   253→      <h3>Leaner than a Blademaster with Wind Walk.</h3>
   254→      <p class="section-desc">
   255→        Tree-shakeable ESM. Import only what you need. Average component weighs under 1.4kb gzipped.
   256→      </p>
