    56→function drawHorizontallyTiledEdge(
    57→  ctx: CanvasRenderingContext2D,
    58→  tile: HTMLCanvasElement,
    59→  x: number,
    60→  y: number,
    61→  width: number,
    62→  height: number,
    63→) {
    64→  if (width <= 0 || height <= 0) return;
    65→
    66→  let drawn = 0;
    67→  while (drawn < width) {
    68→    const segmentW = Math.min(height, width - drawn);
    69→    const srcW = (segmentW / height) * tile.width;
    70→    ctx.drawImage(tile, 0, 0, srcW, tile.height, x + drawn, y, segmentW, height);
    71→    drawn += segmentW;
    72→  }
    73→}
