    75→function fillRoundedRect(
    76→  ctx: CanvasRenderingContext2D,
    77→  x: number,
    78→  y: number,
    79→  width: number,
    80→  height: number,
    81→  radius: number,
    82→) {
    83→  const r = Math.max(0, Math.min(radius, width * 0.5, height * 0.5));
    84→  if (r <= 0) {
    85→    ctx.fillRect(x, y, width, height);
    86→    return;
    87→  }
    88→  ctx.beginPath();
    89→  ctx.moveTo(x + r, y);
    90→  ctx.lineTo(x + width - r, y);
    91→  ctx.quadraticCurveTo(x + width, y, x + width, y + r);
    92→  ctx.lineTo(x + width, y + height - r);
    93→  ctx.quadraticCurveTo(x + width, y + height, x + width - r, y + height);
    94→  ctx.lineTo(x + r, y + height);
    95→  ctx.quadraticCurveTo(x, y + height, x, y + height - r);
    96→  ctx.lineTo(x, y + r);
    97→  ctx.quadraticCurveTo(x, y, x + r, y);
    98→  ctx.closePath();
    99→  ctx.fill();
