   102→function drawEditBoxFrame(canvas: HTMLCanvasElement, borderImg: HTMLImageElement, fillColor: string) {
   103→  const cssW = Math.max(1, canvas.clientWidth || 1);
   104→  const cssH = Math.max(1, canvas.clientHeight || 1);
   105→  const dpr = window.devicePixelRatio || 1;
   106→  const pxW = Math.max(1, Math.round(cssW * dpr));
   107→  const pxH = Math.max(1, Math.round(cssH * dpr));
   108→  if (canvas.width !== pxW || canvas.height !== pxH) {
   109→    canvas.width = pxW;
   110→    canvas.height = pxH;
   111→  }
   112→
   113→  const ctx = canvas.getContext('2d');
   114→  if (!ctx) return;
   115→  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
   116→  ctx.clearRect(0, 0, cssW, cssH);
   117→  ctx.imageSmoothingEnabled = true;
   118→
   119→  const atlasW = borderImg.width;
   120→  const atlasH = borderImg.height;
   121→  const cellW = atlasW / 8;
   122→  const sourceCornerMax = Math.max(1, Math.floor(Math.min(cellW, atlasH)));
   123→  const corner = Math.max(1, Math.floor(Math.min(cssH * editBoxCornerRatio, sourceCornerMax, cssW / 2, cssH / 2)));
   124→  const inset = Math.max(0, Math.floor(Math.min(cssH * editBoxInsetRatio, cssW / 2, cssH / 2)));
   125→  const fillInset = inset + Math.max(1, Math.floor(cssH * 0.02));
   126→  const innerX = fillInset;
   127→  const innerY = fillInset;
   128→  const innerW = Math.max(0, cssW - fillInset * 2);
   129→  const innerH = Math.max(0, cssH - fillInset * 2);
   130→  const innerRadius = Math.max(1, Math.floor(corner * 0.42));
   131→
   132→  if (innerW > 0 && innerH > 0) {
   133→    ctx.save();
   134→    ctx.globalAlpha = 0.88;
   135→    ctx.fillStyle = fillColor;
   136→    fillRoundedRect(ctx, innerX, innerY, innerW, innerH, innerRadius);
   137→    ctx.restore();
   138→  }
   139→
   140→  const drawCell = (idx: number, x: number, y: number, w: number, h: number) => {
   141→    ctx.drawImage(borderImg, idx * cellW, 0, cellW, atlasH, x, y, w, h);
   142→  };
   143→
   144→  drawCell(4, 0, 0, corner, corner);
   145→  drawCell(5, cssW - corner, 0, corner, corner);
   146→  drawCell(6, 0, cssH - corner, corner, corner);
   147→  drawCell(7, cssW - corner, cssH - corner, corner, corner);
   148→
   149→  const edgeH = cssH - corner * 2;
   150→  if (edgeH > 0) {
   151→    drawCell(0, 0, corner, corner, edgeH);
   152→    drawCell(1, cssW - corner, corner, corner, edgeH);
   153→  }
   154→
   155→  const edgeW = cssW - corner * 2;
   156→  if (edgeW > 0) {
   157→    const topRot = rotateCellClockwise(borderImg, 2, cellW, atlasH);
   158→    const bottomRot = rotateCellClockwise(borderImg, 3, cellW, atlasH);
   159→    drawHorizontallyTiledEdge(ctx, topRot, corner, 0, edgeW, corner);
   160→    drawHorizontallyTiledEdge(ctx, bottomRot, corner, cssH - corner, edgeW, corner);
   161→  }
   162→}
