   164→function getHexTextColor(hexColor: string): string {
   165→  const hex = hexColor.replace('#', '');
   166→  const normalized = hex.length === 3
   167→    ? hex.split('').map((ch) => `${ch}${ch}`).join('')
   168→    : hex.padEnd(6, '0').slice(0, 6);
   169→  const r = parseInt(normalized.slice(0, 2), 16);
   170→  const g = parseInt(normalized.slice(2, 4), 16);
   171→  const b = parseInt(normalized.slice(4, 6), 16);
   172→  const luminance = (r * 299 + g * 587 + b * 114) / 1000;
   173→  return luminance > 160 ? '#10151f' : '#f5f8ff';
   174→}
