   176→function TokenSwatch(props: TokenSwatchProps) {
   177→  let canvasRef!: HTMLCanvasElement;
   178→  let renderNonce = 0;
   179→  let destroyed = false;
   180→
   181→  const renderSwatch = async () => {
   182→    const canvas = canvasRef;
   183→    if (!canvas || destroyed) return;
   184→    const color = props.color;
   185→    const atlasUrl = props.borderAtlasUrl;
   186→    const currentNonce = ++renderNonce;
   187→
   188→    if (!atlasUrl) {
   189→      const ctx = canvas.getContext('2d');
   190→      if (!ctx) return;
   191→      const cssW = Math.max(1, canvas.clientWidth || 1);
   192→      const cssH = Math.max(1, canvas.clientHeight || 1);
   193→      const dpr = window.devicePixelRatio || 1;
   194→      const pxW = Math.max(1, Math.round(cssW * dpr));
   195→      const pxH = Math.max(1, Math.round(cssH * dpr));
   196→      if (canvas.width !== pxW || canvas.height !== pxH) {
   197→        canvas.width = pxW;
   198→        canvas.height = pxH;
   199→      }
   200→      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
   201→      ctx.clearRect(0, 0, cssW, cssH);
   202→      ctx.fillStyle = color;
   203→      ctx.fillRect(0, 0, cssW, cssH);
   204→      return;
   205→    }
   206→
   207→    try {
   208→      const borderImg = await loadDataUrlImage(atlasUrl);
   209→      if (destroyed || currentNonce !== renderNonce) return;
   210→      drawEditBoxFrame(canvas, borderImg, color);
   211→    } catch (err) {
   212→      console.error(err);
   213→    }
   214→  };
   215→
   216→  createEffect(() => {
   217→    props.color;
   218→    props.borderAtlasUrl;
   219→    void renderSwatch();
   220→  });
   221→
   222→  onMount(() => {
   223→    const resizeObserver = new ResizeObserver(() => {
   224→      void renderSwatch();
   225→    });
   226→    resizeObserver.observe(canvasRef);
   227→
   228→    onCleanup(() => {
   229→      destroyed = true;
   230→      resizeObserver.disconnect();
   231→    });
   232→  });
   233→
   234→  return (
   235→    <div class="token-swatch token-swatch--editbox-canvas">
   236→      <canvas ref={canvasRef} class="token-swatch-canvas" />
   237→      <span class="token-hex" style={{ '--token-hex-color': props.textColor }}>{props.color}</span>
   238→    </div>
   239→  );
   240→}
