    46→function shouldForceOpaqueOnZeroAlpha(path: string): boolean {
    47→  return /\/buttons\/esc\/[^/]+\/[^/]+-options-(?:menu|button)-background(?:-down|-disabled)?\.blp$/i.test(path);
    48→}
