    50→async function loadBlpDataUrl(path: string): Promise<string> {
    51→  const cached = blpDataUrlCache.get(path);
    52→  if (cached) return cached;
    53→
    54→  const promise = (async () => {
    55→    const res = await fetch(path);
    56→    if (!res.ok) throw new Error(`Failed to fetch ${path}`);
    57→    const ab = await res.arrayBuffer();
    58→    const blp = decodeBLP(ab);
    59→    const img = getBLPImageData(blp, 0);
    60→    const pixelData = new Uint8ClampedArray(img.data);
    61→
    62→    if (shouldForceOpaqueOnZeroAlpha(path)) {
    63→      let allAlphaZero = true;
    64→      for (let i = 3; i < pixelData.length; i += 4) {
    65→        if (pixelData[i] !== 0) {
    66→          allAlphaZero = false;
    67→          break;
    68→        }
    69→      }
    70→      if (allAlphaZero) {
    71→        for (let i = 3; i < pixelData.length; i += 4) {
    72→          pixelData[i] = 255;
    73→        }
    74→      }
    75→    }
    76→
    77→    const canvas = document.createElement('canvas');
    78→    canvas.width = img.width;
    79→    canvas.height = img.height;
    80→    const ctx = canvas.getContext('2d');
    81→    if (!ctx) throw new Error(`Failed to decode ${path}`);
    82→    ctx.putImageData(new ImageData(pixelData, img.width, img.height), 0, 0);
    83→    return canvas.toDataURL('image/png');
    84→  })();
    85→
    86→  blpDataUrlCache.set(path, promise);
    87→  return promise;
    88→}
