   227→  const edgeH = cssH - corner * 2;
   228→  if (edgeH > 0) {
   229→    drawCell(0, 0, corner, corner, edgeH);
   230→    drawCell(1, cssW - corner, corner, corner, edgeH);
   231→  }
   232→
   233→  const edgeW = cssW - corner * 2;
   234→  if (edgeW > 0) {
   235→    const topRot = rotateCellClockwise(borderImg, 2, cellW, atlasH);
   236→    const bottomRot = rotateCellClockwise(borderImg, 3, cellW, atlasH);
   237→    ctx.drawImage(topRot, corner, 0, edgeW, corner);
   238→    ctx.drawImage(bottomRot, corner, cssH - corner, edgeW, corner);
   239→  }
   240→
   241→  if (hovered && hoverImg) {
   242→    const temp = document.createElement('canvas');
   243→    temp.width = pxW;
   244→    temp.height = pxH;
   245→    const tCtx = temp.getContext('2d');
   246→    if (tCtx) {
   247→      tCtx.setTransform(dpr, 0, 0, dpr, 0, 0);
   248→      tCtx.drawImage(canvas, 0, 0, cssW, cssH);
   249→      tCtx.globalCompositeOperation = 'source-in';
   250→      tCtx.drawImage(hoverImg, 0, 0, cssW, cssH);
   251→      ctx.save();
   252→      ctx.globalCompositeOperation = 'lighter';
   253→      ctx.drawImage(temp, 0, 0, cssW, cssH);
   254→      ctx.restore();
   255→    }
   256→  }
   257→}
