   389→export default function FactionPreviewSection() {
   390→  const [raceAssets, setRaceAssets] = createSignal<Record<Race, RacePreviewAssets>>(EMPTY_RACE_PREVIEW_ASSET_MAP);
   391→  const [sliderTrackBgUrl, setSliderTrackBgUrl] = createSignal('');
   392→  const [sliderTrackBorderAtlasUrl, setSliderTrackBorderAtlasUrl] = createSignal('');
   393→  const [resizeTick, setResizeTick] = createSignal(0);
   394→
   395→  onMount(() => {
   396→    let cancelled = false;
   397→
   398→    void Promise.all([
   399→      Promise.all(
   400→        previewRaces.map(async ({ race }) => {
   401→          const prefix = RACE_PREFIXES[race];
   402→          const escSkin = getEscButtonSkin(race);
   403→          const [escBgUrl, escBgDownUrl, escBorderUrl, escBorderDownUrl, escHoverUrl, sliderKnobUrl] = await Promise.all([
   404→            loadBlpDataUrl(escSkin.bg),
   405→            loadBlpDataUrl(escSkin.bgDown),
   406→            loadBlpDataUrl(escSkin.border),
   407→            loadBlpDataUrl(escSkin.borderDown),
   408→            loadBlpDataUrl(escSkin.hover),
   409→            loadBlpDataUrl(getEscSliderKnobPath(race)),
   410→          ]);
   411→
   412→          return [
   413→            race,
   414→            {
   415→              escBgUrl,
   416→              escBgDownUrl,
   417→              escBorderUrl,
   418→              escBorderDownUrl,
   419→              escHoverUrl,
   420→              sliderKnobUrl,
   421→            } satisfies RacePreviewAssets,
   422→          ] as const;
   423→        }),
   424→      ),
   425→      loadBlpDataUrl('/buttons/slider/slider-background.blp'),
   426→      loadBlpDataUrl('/buttons/slider/slider-border.blp'),
   427→    ])
   428→      .then(([entries, sliderBg, sliderBorder]) => {
   429→        if (cancelled) return;
   430→        const next: Record<Race, RacePreviewAssets> = {
   431→          Human: { ...EMPTY_RACE_PREVIEW_ASSETS },
   432→          Orc: { ...EMPTY_RACE_PREVIEW_ASSETS },
   433→          NightElf: { ...EMPTY_RACE_PREVIEW_ASSETS },
   434→          Undead: { ...EMPTY_RACE_PREVIEW_ASSETS },
   435→        };
   436→        for (const [race, assets] of entries) {
   437→          next[race] = assets;
   438→        }
   439→        setRaceAssets(next);
   440→        setSliderTrackBgUrl(sliderBg);
   441→        setSliderTrackBorderAtlasUrl(sliderBorder);
   442→      })
   443→      .catch((err) => console.error(err));
   444→
   445→    const onResize = () => setResizeTick((value) => value + 1);
   446→    window.addEventListener('resize', onResize);
   447→
   448→    onCleanup(() => {
   449→      cancelled = true;
   450→      window.removeEventListener('resize', onResize);
   451→    });
   452→  });
   453→
   454→  return (
   455→    <section class="section-card faction-preview-section">
   456→      <p class="section-desc">
   457→        Every component adapts to your chosen faction. One prop changes everything. We wish CSS had thought of this.
   458→      </p>
   459→      <div class="faction-preview">
   460→        <For each={previewRaces}>
   461→          {({ race, label }) => (
   462→            <FactionPreviewCard
   463→              race={race}
   464→              label={label}
   465→              assets={() => raceAssets()[race]}
   466→              sliderTrackBgUrl={sliderTrackBgUrl}
   467→              sliderTrackBorderAtlasUrl={sliderTrackBorderAtlasUrl}
   468→              resizeTick={resizeTick}
   469→            />
   470→          )}
   471→        </For>
   472→      </div>
   473→    </section>
   474→  );
   475→}
