import { useState, useEffect } from 'react';
import { ALL_BORDER_PATHS, BORDER_CATEGORIES } from '../../data/borderManifest';

interface Props {
  loadBlpDataUrl: (path: string) => Promise<string>;
}

interface BorderRenderEntry {
  previewUrl: string;
